import React, {useState} from 'react'
import {fadeInDown} from "react-animations";
import styled, { keyframes } from 'styled-components';
import {CSSTransition,SwitchTransition} from 'react-transition-group'
const HistoryOfMe = () => {
    const [isShown, SetIsShown] = useState(false);

    const FadeInDown = styled.div`animation: 2s ${keyframes`${fadeInDown}`} 1 `;
    const toggleState = () => SetIsShown(!isShown);



    return(
        <div>
            { !isShown &&(
                <div className="ui center segment">
                <button className="ui inverted green button" onClick={toggleState}>
                    Why did I start coding?
                </button>
                </div>
            )
            }
        {isShown && (
            <div className="ui center segment">
                <button className="ui filled red button" onClick={toggleState}>
                    Close?
                </button>
                <p className="aboutMe">
                    My journey to code began around 2017, when I was in the Korean Army. Prior to this, I was studying to become a personal trainer in the United States.<br/><br/>
                    It was a difficult choice, as I had lived in the U.S for over 10 years and I had to stop my education and go back to South Korea, where I was born, to carry out the mandatory military service.
                    There, I was able to gain fresh perspective about what life is about and what I should do after the military. <br/><br/>To give perspective as to why this was so effective, I was only able to access the internet for 1 hour per day and was not allowed to have a phone.
                    Therefore, I was forced to go through what people call, "detox" from the social media and the internet overall. It was also during this time, I had witnessed Deep Mind's AlphaGo, absolutely dominating the South Korea's well-known grandmaster Lee Sedol. It was this very moment, when I had become fully invested in learning how to code.
                </p>

            </div>
            )
        }
        </div>



    )
};

export default HistoryOfMe;
